        <Route path="/" element={<Login />} />

        {/* Protected routes - only accessible after login */}
        <Route 
          path="/home" 
          element={
            <ProtectedRoute>
              <NavBar />
              <Carousel />
              <Footer />
            </ProtectedRoute>
          } 
        />

        <Route
          path="/profile"
